
import { describe, it, expect } from 'vitest';
import { getSanctuaryForObserver, restAtSanctuary } from '../void-sanctuaries';
import { createObserver } from '../void-game-engine';
import { calculateEnergyCapacity } from '../void-dimensional-mastery';

describe('void-sanctuaries', () => {
  it('uniquely maps a sanctuary to an observer and restores energy', () => {
    const observer = createObserver('did:1', 1234, 'mystic', 'scientist', 'boson');
    // drain some energy
    const tiredObserver = { ...observer, energy: 5, ploSinceLastFailure: 100 };
    
    // find sanctuary
    const sanctuary = getSanctuaryForObserver(tiredObserver, 0);
    expect(sanctuary.majorPhyle).toBe('mystic');
    
    // move observer to sanctuary exactly
    const restingObserver = { ...tiredObserver, coordinate: sanctuary.coordinate };
    
    // rest
    const result = restAtSanctuary(restingObserver);
    expect(result.state.ploSinceLastFailure).toBe(0);
    expect(result.state.energy).toBe(calculateEnergyCapacity(0));
  });
});
